import { Injectable } from '@nestjs/common';
import { Logger } from '@regask/common-lib/logger/logger.service';
import { BaseAtlasSearchFilterQuery } from '@regask/common-lib/repositories/atlas-search-filter-query/base';
import { SearchOperatorQueryType } from '@regask/common-lib/repositories/atlas-search-filter-query/types';
import {
  AtlasSearchFilterKey,
  AtlasSearchFilterOperator,
} from '@regask/common-lib/types/atlas-search-filter-key';
import { BaseUseCase, UseCaseResult } from '@regask/common-lib/workflow';
import { PipelineStage } from 'mongoose';

import { {{entity_name}}Entity } from '@/cores/entities/__TBD__/entity';
import { {{entity_name}}Repository } from '@/cores/repositories/__TBD__/repository';

import { MapDataGridFilterToAtlasSearchFilterConcern } from './concerns/map-data-grid-filter-to-atlas-search-filter.concern';
import { GridFilterModel } from './concerns/types';
import {
  DEFAULT_SORT_CONFIG,
  FIELD_TO_DB_PATH,
  SEARCHABLE_DB_PATHS,
  SORTABLE_FIELDS,
} from './enums';
import { {{usecase_name}}UseCaseTypes } from './types';

@Injectable()
export class {{usecase_name}}UseCase extends BaseUseCase<
  {{usecase_name}}UseCaseTypes.Input,
  {{usecase_name}}UseCaseTypes.Output
> {
  constructor(
    private {{entity_name_camel}}Repository: {{entity_name}}Repository,
    private mapDataGridFilterConcern: MapDataGridFilterToAtlasSearchFilterConcern,
  ) {
    super();
    this.logger = new Logger({{usecase_name}}UseCase.name);
  }

  async handle(
    input: {{usecase_name}}UseCaseTypes.Input,
  ): Promise<UseCaseResult<{{usecase_name}}UseCaseTypes.Output>> {
    this.logger.info(`Executing {{usecase_name}}UseCase`, { input });

    const searchFilter = this.#buildSearchFilter(input);
    const [total, items] = await Promise.all([
      this.#getFilteredRecordCount(searchFilter),
      this.#executeSearchQuery(input, searchFilter),
    ]);

    return {
      error: null,
      data: { total, items },
    };
  }

  #buildSearchFilter(input: {{usecase_name}}UseCaseTypes.Input): SearchOperatorQueryType {
    return new BaseAtlasSearchFilterQuery({
      operator: AtlasSearchFilterOperator.And,
      value: [
        this.#buildCompanyFilter(input),
        this.#buildDataGridFilter(input),
        this.#buildFullTextSearchFilter(input),
      ].filter(Boolean),
      options: { safeGenerate: true },
    }).generate();
  }

  #buildCompanyFilter(input: {{usecase_name}}UseCaseTypes.Input): AtlasSearchFilterKey {
    return {
      operator: AtlasSearchFilterOperator.Equal,
      attribute: 'companyId',
      value: input.companyId,
    };
  }

  #buildDataGridFilter(
    input: {{usecase_name}}UseCaseTypes.Input,
  ): AtlasSearchFilterKey | null {
    if (!input.filter?.items?.length) return null;
    const result = this.mapDataGridFilterConcern.execute({
      ...input.filter,
      items: input.filter.items,
    } as GridFilterModel);
    return result.value?.length ? result : null;
  }

  #buildFullTextSearchFilter(
    input: {{usecase_name}}UseCaseTypes.Input,
  ): AtlasSearchFilterKey | null {
    if (!input.searchKey?.trim()) return null;
    return {
      operator: AtlasSearchFilterOperator.Search,
      value: input.searchKey,
      options: { path: SEARCHABLE_DB_PATHS, matchCriteria: 'all' },
    };
  }

  #buildSearchPipeline(
    searchFilter: SearchOperatorQueryType,
    sortConfig: Record<string, 1 | -1>,
  ): PipelineStage.Search['$search'] {
    return {
      index: 'globalSearch',
      returnStoredSource: true,
      ...searchFilter,
      sort: sortConfig,
    } as any;
  }

  #buildSearchPipelineForCount(
    searchFilter: SearchOperatorQueryType,
  ): PipelineStage.Search['$search'] {
    return {
      index: 'globalSearch',
      ...searchFilter,
      count: { type: 'total' },
    } as any;
  }

  async #getFilteredRecordCount(searchFilter: SearchOperatorQueryType): Promise<number> {
    const countResult = await this.{{entity_name_camel}}Repository.aggregateWithSearch({
      search: this.#buildSearchPipelineForCount(searchFilter) as any,
      pipeline: [{ $project: { searchMeta: '$$SEARCH_META' } }, { $limit: 1 }],
    });
    return countResult[0]?.searchMeta?.count?.total ?? 0;
  }

  async #executeSearchQuery(
    input: {{usecase_name}}UseCaseTypes.Input,
    searchFilter: SearchOperatorQueryType,
  ): Promise<{{entity_name}}Entity[]> {
    const sortConfig = this.#buildSortConfig(input);
    return this.{{entity_name_camel}}Repository.aggregateWithSearch<{{entity_name}}Entity>({
      search: this.#buildSearchPipeline(searchFilter, sortConfig) as any,
      pipeline: [...this.#skipPipeline(input), ...this.#limitPipeline(input)],
    });
  }

  #skipPipeline(input: {{usecase_name}}UseCaseTypes.Input): PipelineStage.Skip[] {
    const { page, limit } = input.pagination || {};
    const skip = page && limit ? (page - 1) * limit : 0;
    return skip ? [{ $skip: skip }] : [];
  }

  #limitPipeline(input: {{usecase_name}}UseCaseTypes.Input): PipelineStage.Limit[] {
    const limit = input.pagination?.limit;
    return limit ? [{ $limit: limit }] : [];
  }

  #mapFieldToDbPath(field: string): string {
    return FIELD_TO_DB_PATH[field] || field;
  }

  #buildSortConfig(input: {{usecase_name}}UseCaseTypes.Input): Record<string, 1 | -1> {
    if (input.sorts?.length) {
      const sortConfig: Record<string, 1 | -1> = {};
      for (const sort of input.sorts) {
        if (sort.sortBy && SORTABLE_FIELDS.has(sort.sortBy)) {
          sortConfig[this.#mapFieldToDbPath(sort.sortBy)] = sort.sortDirection === 'asc' ? 1 : -1;
        }
      }
      if (Object.keys(sortConfig).length) return sortConfig;
    }

    if (input.sortBy && SORTABLE_FIELDS.has(input.sortBy)) {
      return { [this.#mapFieldToDbPath(input.sortBy)]: input.sortDirection === 'asc' ? 1 : -1 };
    }

    return DEFAULT_SORT_CONFIG;
  }
}

